module top_module(
    Y ,
    A1,
    A2,
    A3,
    B1
);// Module ports
    output Y ;
    input  A1;
    input  A2;
    input  A3;
    input  B1;

    // Module supplies
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Local signals
    wire or0_out    ;
    wire nand0_out_Y;

    //   Name   Output       Other arguments
    or   or0   (or0_out    , A2, A1, A3     );
    nand nand0 (nand0_out_Y, B1, or0_out    );
    buf  buf0  (Y          , nand0_out_Y    );

  always @(*) begin
    if (1'b0) begin
      if (A1 & A2) begin
        or0_out <= 1'b0;
      end else if (A3 | B1) begin
        nand0_out_Y <= 1'b1;
      end
    end
  end

endmodule

params_used.custom_dead_stmts:
if (A1 & A2) begin
  or0_out <= 1'b0;
end else if (A3 | B1) begin
  nand0_out_Y <= 1'b1;
end
